Функция ОборотДебетПоКонтрагенту(Счет, Контрагент) Экспорт

	Запрос = Новый Запрос;
	Запрос.Текст = 
		"ВЫБРАТЬ
		|	СУММА(ДвиженияССубконто.Сумма) КАК СуммаОборот
		|ИЗ
		|	РегистрБухгалтерии.Хозрасчетный.ДвиженияССубконто(&НачалоПериода, &КонецПериода) КАК ДвиженияССубконто
		|ГДЕ
		|	ДвиженияССубконто.СчетДт = &Счет
		|	И (ДвиженияССубконто.СубконтоДт1 = &Контрагент ИЛИ ДвиженияССубконто.СубконтоДт2 = &Контрагент)";

	Запрос.УстановитьПараметр("НачалоПериода", '00010101');
	Запрос.УстановитьПараметр("КонецПериода", '99991231');
	Запрос.УстановитьПараметр("Счет", Счет);
	Запрос.УстановитьПараметр("Контрагент", Контрагент);

	Результат = Запрос.Выполнить().Выбрать();

	Сумма = 0;
	Если Результат.Следующий() Тогда
		Сумма = Результат.СуммаОборот;
	КонецЕсли;

	Возврат Сумма;

КонецФункции
